:root {
  --card-bg: #1a1a2e;
  --album-bg: #16213e;
  --accent: #e94560;
  --accent-soft: #ff6b6b;
  --highlight: #0f3460;
  --text-primary: #eaeaea;
  --text-secondary: #a0a0c0;
  --disc-outer: #2a2a4a;
  --disc-inner: #1e1e38;
  --disc-center: #e94560;
  --progress-track: #2e2e50;
  --progress-fill: #e94560;
  --progress-thumb: #ffffff;
  --ctrl-bg: #0f3460;
  --ctrl-hover: #e94560;
  --tag-bg: #0f3460;
  --tag-text: #a0c4ff;
  --genre-bg: #e94560;
  --genre-text: #ffffff;
}

body {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  margin: 0;
}

.player-card {
  display: flex;
  flex-direction: column;
  width: 300px;
  background: var(--card-bg);
  border-radius: 20px;
  overflow: hidden;
  border: 1px solid var(--highlight);
}

.album-art {
  position: relative;
  background: var(--album-bg);
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 28px 0;
  border-bottom: 1px solid var(--highlight);
}

.art-inner {
  position: relative;
  width: 100px;
  height: 100px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.disc-ring {
  position: absolute;
  border-radius: 50%;
  border: 3px solid var(--disc-outer);
}

.outer-ring {
  width: 100px;
  height: 100px;
  background: var(--disc-outer);
}

.inner-ring {
  width: 68px;
  height: 68px;
  background: var(--disc-inner);
  border-color: var(--disc-inner);
}

.disc-center {
  position: absolute;
  width: 22px;
  height: 22px;
  border-radius: 50%;
  background: var(--disc-center);
  z-index: 2;
}

.genre-tag {
  position: absolute;
  top: 12px;
  right: 14px;
  background: var(--genre-bg);
  color: var(--genre-text);
  font-size: 10px;
  font-weight: 700;
  padding: 3px 8px;
  border-radius: 20px;
  letter-spacing: 0.5px;
  text-transform: uppercase;
}

.player-info {
  display: flex;
  flex-direction: column;
  gap: 14px;
  padding: 18px 20px 20px;
}

.track-meta {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.track-title {
  font-size: 18px;
  font-weight: 700;
  color: var(--text-primary);
  line-height: 1.2;
}

.track-artist {
  font-size: 13px;
  font-weight: 400;
  color: var(--text-secondary);
}

.progress-section {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.progress-bar {
  position: relative;
  height: 4px;
  background: var(--progress-track);
  border-radius: 4px;
  display: flex;
  align-items: center;
}

.progress-fill {
  width: 43%;
  height: 100%;
  background: var(--progress-fill);
  border-radius: 4px;
}

.progress-thumb {
  position: absolute;
  left: 43%;
  width: 12px;
  height: 12px;
  border-radius: 50%;
  background: var(--progress-thumb);
  transform: translateX(-50%);
}

.time-labels {
  display: flex;
  justify-content: space-between;
  font-size: 11px;
  color: var(--text-secondary);
}

.controls {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 12px;
}

.ctrl-btn {
  border: none;
  cursor: pointer;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--ctrl-bg);
  color: var(--text-primary);
  font-size: 13px;
}

.skip-btn {
  width: 36px;
  height: 36px;
}

.play-btn {
  width: 48px;
  height: 48px;
  background: var(--accent);
  font-size: 18px;
  padding-left: 3px;
}

.extras {
  display: flex;
  gap: 8px;
}

.extra-tag {
  background: var(--tag-bg);
  color: var(--tag-text);
  font-size: 11px;
  font-weight: 600;
  padding: 4px 10px;
  border-radius: 20px;
}
